рЯЫТ Real-World E-Commerce Example

<Swiper
modules={[Navigation, Pagination]}
navigation
pagination={{ clickable: true }}
spaceBetween={20}
breakpoints={{
640: { slidesPerView: 2 },
768: { slidesPerView: 3 },
1024: { slidesPerView: 4 },
}}
>
{products.map((product) => (
<SwiperSlide key={product.id}>
<ProductCard product={product} />
</SwiperSlide>
